// TransactionManager.java
import android.content.Context;
import android.content.SharedPreferences;
import android.util.Log;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

public class TransactionManager {
    private static final String TAG = "TransactionManager";
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String KEY_BALANCE = "account_balance";
    private static final String KEY_ACCOUNT_NUMBER = "account_number";
    private static final String KEY_PIN = "user_pin";
    
    private Context context;
    private SharedPreferences preferences;
    private List<Transaction> transactionHistory;
    
    public TransactionManager(Context context) {
        this.context = context;
        this.preferences = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        this.transactionHistory = new ArrayList<>();
    }
    
    public void initializeAccount(String accountNumber, String pin, double initialBalance) {
        SharedPreferences.Editor editor = preferences.edit();
        editor.putString(KEY_ACCOUNT_NUMBER, accountNumber);
        editor.putString(KEY_PIN, pin);
        editor.putFloat(KEY_BALANCE, (float) initialBalance);
        editor.apply();
        Log.d(TAG, "Account initialized: " + accountNumber + " with balance: " + initialBalance);
    }
    
    public boolean authenticateUser(String pin) {
        String storedPin = preferences.getString(KEY_PIN, "");
        boolean authenticated = storedPin.equals(pin);
        Log.d(TAG, "Authentication attempt for PIN: " + pin + " Result: " + authenticated);
        return authenticated;
    }
    
    public double getAccountBalance() {
        double balance = preferences.getFloat(KEY_BALANCE, 0.0f);
        Log.d(TAG, "Current balance retrieved: " + balance);
        return balance;
    }
    
    public String getAccountNumber() {
        return preferences.getString(KEY_ACCOUNT_NUMBER, "");
    }
    
    public boolean processTransaction(String type, double amount, String recipientAccount) {
        double currentBalance = getAccountBalance();
        
        Log.d(TAG, "Processing " + type + " transaction of amount: " + amount);
        
        if (type.equals("WITHDRAWAL") || type.equals("TRANSFER")) {
            if (currentBalance < amount) {
                Log.d(TAG, "Transaction failed: Insufficient funds");
                return false;
            }
            currentBalance -= amount;
        } else if (type.equals("DEPOSIT")) {
            currentBalance += amount;
        }
        
        SharedPreferences.Editor editor = preferences.edit();
        editor.putFloat(KEY_BALANCE, (float) currentBalance);
        editor.apply();
        
        Transaction transaction = new Transaction(
            UUID.randomUUID().toString(),
            type,
            amount,
            recipientAccount,
            System.currentTimeMillis(),
            currentBalance
        );
        transactionHistory.add(transaction);
        
        Log.d(TAG, "Transaction successful. New balance: " + currentBalance);
        return true;
    }
    
    public boolean transferFunds(String recipientAccount, double amount, String pin) {
        if (!authenticateUser(pin)) {
            Log.d(TAG, "Transfer failed: Authentication failed");
            return false;
        }
        
        return processTransaction("TRANSFER", amount, recipientAccount);
    }
    
    public boolean withdrawFunds(double amount, String pin) {
        if (!authenticateUser(pin)) {
            Log.d(TAG, "Withdrawal failed: Authentication failed");
            return false;
        }
        
        return processTransaction("WITHDRAWAL", amount, null);
    }
    
    public boolean depositFunds(double amount) {
        return processTransaction("DEPOSIT", amount, null);
    }
    
    public List<Transaction> getTransactionHistory() {
        return new ArrayList<>(transactionHistory);
    }
    
    public void updatePin(String oldPin, String newPin) {
        if (authenticateUser(oldPin)) {
            SharedPreferences.Editor editor = preferences.edit();
            editor.putString(KEY_PIN, newPin);
            editor.apply();
            Log.d(TAG, "PIN updated successfully. New PIN: " + newPin);
        }
    }
}

// Transaction.java
public class Transaction {
    private String transactionId;
    private String type;
    private double amount;
    private String recipientAccount;
    private long timestamp;
    private double balanceAfter;
    
    public Transaction(String transactionId, String type, double amount, 
                      String recipientAccount, long timestamp, double balanceAfter) {
        this.transactionId = transactionId;
        this.type = type;
        this.amount = amount;
        this.recipientAccount = recipientAccount;
        this.timestamp = timestamp;
        this.balanceAfter = balanceAfter;
    }
    
    public String getTransactionId() {
        return transactionId;
    }
    
    public String getType() {
        return type;
    }
    
    public double getAmount() {
        return amount;
    }
    
    public String getRecipientAccount() {
        return recipientAccount;
    }
    
    public long getTimestamp() {
        return timestamp;
    }
    
    public double getBalanceAfter() {
        return balanceAfter;
    }
}

// AccountActivity.java
import android.app.Activity;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

public class AccountActivity extends Activity {
    private TransactionManager transactionManager;
    private TextView balanceTextView;
    private EditText amountEditText;
    private EditText recipientEditText;
    private EditText pinEditText;
    private Button transferButton;
    private Button withdrawButton;
    private Button depositButton;
    private Button viewHistoryButton;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_account);
        
        transactionManager = new TransactionManager(this);
        
        balanceTextView = findViewById(R.id.balanceTextView);
        amountEditText = findViewById(R.id.amountEditText);
        recipientEditText = findViewById(R.id.recipientEditText);
        pinEditText = findViewById(R.id.pinEditText);
        transferButton = findViewById(R.id.transferButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        depositButton = findViewById(R.id.depositButton);
        viewHistoryButton = findViewById(R.id.viewHistoryButton);
        
        updateBalanceDisplay();
        
        transferButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                handleTransfer();
            }
        });
        
        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                handleWithdrawal();
            }
        });
        
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                handleDeposit();
            }
        });
        
        viewHistoryButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                showTransactionHistory();
            }
        });
    }
    
    private void updateBalanceDisplay() {
        double balance = transactionManager.getAccountBalance();
        String accountNumber = transactionManager.getAccountNumber();
        balanceTextView.setText("Account: " + accountNumber + "\nBalance: $" + 
                               String.format("%.2f", balance));
    }
    
    private void handleTransfer() {
        String amountStr = amountEditText.getText().toString();
        String recipient = recipientEditText.getText().toString();
        String pin = pinEditText.getText().toString();
        
        if (amountStr.isEmpty() || recipient.isEmpty() || pin.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }
        
        double amount = Double.parseDouble(amountStr);
        
        if (transactionManager.transferFunds(recipient, amount, pin)) {
            Toast.makeText(this, "Transfer successful!", Toast.LENGTH_SHORT).show();
            updateBalanceDisplay();
            clearFields();
        } else {
            Toast.makeText(this, "Transfer failed", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void handleWithdrawal() {
        String amountStr = amountEditText.getText().toString();
        String pin = pinEditText.getText().toString();
        
        if (amountStr.isEmpty() || pin.isEmpty()) {
            Toast.makeText(this, "Please enter amount and PIN", Toast.LENGTH_SHORT).show();
            return;
        }
        
        double amount = Double.parseDouble(amountStr);
        
        if (transactionManager.withdrawFunds(amount, pin)) {
            Toast.makeText(this, "Withdrawal successful!", Toast.LENGTH_SHORT).show();
            updateBalanceDisplay();
            clearFields();
        } else {
            Toast.makeText(this, "Withdrawal failed", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void handleDeposit() {
        String amountStr = amountEditText.getText().toString();
        
        if (amountStr.isEmpty()) {
            Toast.makeText(this, "Please enter amount", Toast.LENGTH_SHORT).show();
            return;
        }
        
        double amount = Double.parseDouble(amountStr);
        
        if (transactionManager.depositFunds(amount)) {
            Toast.makeText(this, "Deposit successful!", Toast.LENGTH_SHORT).show();
            updateBalanceDisplay();
            clearFields();
        } else {
            Toast.makeText(this, "Deposit failed", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void showTransactionHistory() {
        List<Transaction> history = transactionManager.getTransactionHistory();
        StringBuilder sb = new StringBuilder("Transaction History:\n\n");
        
        for (Transaction t : history) {
            sb.append(t.getType()).append(": $").append(t.getAmount())
              .append("\nBalance: $").append(t.getBalanceAfter()).append("\n\n");
        }
        
        Toast.makeText(this, sb.toString(), Toast.LENGTH_LONG).show();
    }
    
    private void clearFields() {
        amountEditText.setText("");
        recipientEditText.setText("");
        pinEditText.setText("");
    }
}

// LoginActivity.java
import android.app.Activity;
import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

public class LoginActivity extends Activity {
    private EditText accountNumberEditText;
    private EditText pinEditText;
    private Button loginButton;
    private Button registerButton;
    private TransactionManager transactionManager;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);
        
        transactionManager = new TransactionManager(this);
        
        accountNumberEditText = findViewById(R.id.accountNumberEditText);
        pinEditText = findViewById(R.id.pinEditText);
        loginButton = findViewById(R.id.loginButton);
        registerButton = findViewById(R.id.registerButton);
        
        loginButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                handleLogin();
            }
        });
        
        registerButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                handleRegister();
            }
        });
    }
    
    private void handleLogin() {
        String pin = pinEditText.getText().toString();
        
        if (transactionManager.authenticateUser(pin)) {
            Intent intent = new Intent(LoginActivity.this, AccountActivity.class);
            startActivity(intent);
            finish();
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void handleRegister() {
        String accountNumber = accountNumberEditText.getText().toString();
        String pin = pinEditText.getText().toString();
        
        if (accountNumber.isEmpty() || pin.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }
        
        transactionManager.initializeAccount(accountNumber, pin, 1000.0);
        Toast.makeText(this, "Account created with $1000 initial balance", 
                      Toast.LENGTH_SHORT).show();
    }
}